class Solution {
    private static final long MOD = 1_000_000_007L;

    public int lengthAfterTransformations(String s, int t, List<Integer> nums) {
        long[] cnt = new long[26];
        for (char c : s.toCharArray()) cnt[c - 'a']++;

        long[][] mat = new long[26][26];
        for (int i = 0; i < 26; i++) {
            int k = nums.get(i);
            for (int j = 0; j < k; j++) {
                int col = (i + 1 + j) % 26;
                mat[i][col]++;
            }
        }

        long[][] res = matrixPow(mat, t);
        long ans = 0;
        for (int i = 0; i < 26; i++) {
            for (int j = 0; j < 26; j++) {
                ans = (ans + cnt[i] * res[i][j]) % MOD;
            }
        }
        return (int) ans;
    }

    private long[][] matrixPow(long[][] a, int p) {
        long[][] res = new long[26][26];
        for (int i = 0; i < 26; i++) res[i][i] = 1;

        while (p > 0) {
            if ((p & 1) == 1) res = multiply(res, a);
            a = multiply(a, a);
            p >>= 1;
        }
        return res;
    }

    private long[][] multiply(long[][] a, long[][] b) {
        long[][] c = new long[26][26];
        for (int i = 0; i < 26; i++) {
            for (int k = 0; k < 26; k++) {
                if (a[i][k] == 0) continue;
                for (int j = 0; j < 26; j++) {
                    c[i][j] = (c[i][j] + a[i][k] * b[k][j]) % MOD;
                }
            }
        }
        return c;
    }
}
